"""Dependency-free, standalone analysis-map HTML generation."""

from __future__ import annotations

import json
from collections.abc import Mapping

from .models import Mall, Mesh


MAP_FIELDS = (
    "mesh_id",
    "acquisition_potential_score",
    "population",
    "household_count",
    "age_0_14_population",
    "age_15_64_population",
    "age_65_plus_population",
    "young_adult_ratio",
    "huff_probability",
    "car_choice_index",
    "walk_choice_index",
    "bike_choice_index",
    "car_availability",
    "walk_availability",
    "bike_availability",
    "accessibility_index",
    "commercial_concentration_index",
    "eligible_for_delivery",
    "is_delivery_zone",
    "score_quality_tier",
    "score_coverage",
    "nearest_station_distance_m",
    "nearest_bus_stop_distance_m",
    "parking_count",
    "road_length_m",
    "major_road_length_m",
    "walkable_road_length_m",
    "commercial_poi_total",
    "retail_count",
    "restaurant_count",
    "cafe_count",
    "service_count",
    "entertainment_count",
    "office_count",
    "accessibility_coverage",
    "commercial_coverage",
    "accessibility_used_components",
    "commercial_used_components",
    "used_features",
    "used_weights",
    "score_contributions",
    "required_groups_missing",
)


def _json(value: object) -> str:
    return json.dumps(value, ensure_ascii=False, separators=(",", ":"), sort_keys=True).replace(
        "</", "<\\/"
    )


def _mesh_record(mesh: Mesh) -> list[object]:
    longitudes = [point[0] for point in mesh.polygon]
    latitudes = [point[1] for point in mesh.polygon]
    values = [getattr(mesh, name) for name in MAP_FIELDS]
    return [min(longitudes), min(latitudes), max(longitudes), max(latitudes), *values]


def build_map_html(
    meshes: list[Mesh],
    target: Mall,
    competitors: list[Mall],
    context: Mapping[str, object],
) -> str:
    """Build one deterministic, offline HTML file backed by a compact Canvas payload."""
    threshold = context.get("threshold")
    coverages = [mesh.score_coverage for mesh in meshes if mesh.score_coverage is not None]
    summary = {
        "mesh_count": len(meshes),
        "eligible_count": sum(mesh.eligible_for_delivery for mesh in meshes),
        "delivery_zone_count": sum(mesh.is_delivery_zone for mesh in meshes),
        "threshold": threshold,
        "above_threshold_count": sum(
            mesh.acquisition_potential_score is not None
            and threshold is not None
            and mesh.acquisition_potential_score >= threshold
            for mesh in meshes
        ),
        "ineligible_above_threshold_count": sum(
            mesh.acquisition_potential_score is not None
            and threshold is not None
            and mesh.acquisition_potential_score >= threshold
            and not mesh.eligible_for_delivery
            for mesh in meshes
        ),
        "mean_score_coverage": sum(coverages) / len(coverages) if coverages else None,
    }
    mall_records = [
        {
            "gla": mall.floor_area_m2,
            "id": mall.id,
            "lat": mall.latitude,
            "lon": mall.longitude,
            "name": mall.name,
            "type": "target" if mall is target else "competitor",
            "size_measurement_type": mall.size_measurement_type,
            "size_measurement_label": mall.size_measurement_label,
            "size_measurement_note": mall.size_measurement_note,
            "facility_scope": mall.facility_scope,
        }
        for mall in [target, *competitors]
    ]
    payload = {
        "context": dict(context),
        "fields": ["west", "south", "east", "north", *MAP_FIELDS],
        "malls": mall_records,
        "meshes": [_mesh_record(mesh) for mesh in meshes],
        "summary": summary,
    }
    data = _json(payload)
    title = f"{target.name}｜獲得ポテンシャル分析"
    return _HTML.replace("__TITLE__", title).replace("__MAP_DATA__", data)


